!async function(){const o=window.location.pathname.match(/\/play\/([a-f0-9-]+)/);if(!o)return void console.log("Không tìm thấy quiz ID");const n=`https://quiz.com/api/quiz/${o[1]}/`;try{const o=await fetch(n),l=await o.json();l&&l.slides?(console.clear(),console.log(`%cTổng số câu: ${l.slides.length}`,"color: yellow; font-size: 14px"),l.slides.forEach((o,n)=>{if(!o.question)return;const l=o.question.replace(/<[^>]*>?/gm,"").trim(),c=o.answers,e=o.type;if("Pinpoint"!==e&&"Location"!==e){if(console.log(`%cCÂU ${n+1}: ${l}`,"color: #ffaa00; font-size: 14px; font-weight: bold"),null==c||0==c.length)console.log("%c[Không có đáp án]","color: gray");else{const o=c.filter(o=>!0===o.isCorrect);0===o.length?console.log("%c[Không có đáp án đúng]","color: red"):(console.log("%cĐáp án đúng:","color: #00ff00; font-weight: bold"),o.forEach((n,l)=>{let c=n.text;console.log(`%c${o.length>1?l+1+". ":""}${c}`,"color: #00ff00")}))}console.log("")}})):console.log("Không thể lấy dữ liệu quiz")}catch(o){console.error("Lỗi:",o)}}();